import {createContext, useCallback, useContext, useRef} from 'react';
import type {TextInput} from 'react-native';

export interface KeyboardNavContextValue {
    register: (id: string, ref: React.RefObject<TextInput | null>) => void;
    unregister: (id: string) => void;
    setElementsOrder: (ids: string[]) => void;
    getNavProps: (id: string) => {
        returnKeyType: 'next' | 'done';
        blurOnSubmit: boolean;
        onSubmitEditing: () => void;
    };
    focusNext: (currentId: string) => void;
}

export const KeyboardNavContext = createContext<KeyboardNavContextValue | null>(null);

export const useKeyboardNav = () => useContext(KeyboardNavContext);

/**
 * Creates the keyboard navigation provider value.
 * Maintains a ref registry and element order to wire up
 * returnKeyType / blurOnSubmit / onSubmitEditing on native TextInputs.
 */
export function useKeyboardNavProvider() {
    const refsMap = useRef<Map<string, React.RefObject<TextInput | null>>>(new Map());
    const elementsOrder = useRef<string[]>([]);

    const register = useCallback((id: string, ref: React.RefObject<TextInput | null>) => {
        refsMap.current.set(id, ref);
    }, []);

    const unregister = useCallback((id: string) => {
        refsMap.current.delete(id);
    }, []);

    const setElementsOrder = useCallback((ids: string[]) => {
        elementsOrder.current = ids;
    }, []);

    const getNavProps = useCallback((id: string) => {
        // Filter to only registered (visible) fields
        const visibleOrder = elementsOrder.current.filter(
            (eid) => refsMap.current.has(eid)
        );

        const idx = visibleOrder.indexOf(id);
        // Default to 'next' when field not yet registered (idx === -1 on first render)
        const isLast = idx !== -1 && idx === visibleOrder.length - 1;

        return {
            returnKeyType: isLast ? 'done' as const : 'next' as const,
            blurOnSubmit: isLast,
            // Read from refs at call time via focusNext — avoids stale closure
            onSubmitEditing: () => {
                focusNext(id);
            },
        };
    }, [focusNext]);

    const focusNext = useCallback((currentId: string) => {
        const visibleOrder = elementsOrder.current.filter(
            (eid) => refsMap.current.has(eid)
        );
        const idx = visibleOrder.indexOf(currentId);
        if (idx === -1 || idx === visibleOrder.length - 1) return;
        const nextId = visibleOrder[idx + 1];
        if (nextId) {
            const nextRef = refsMap.current.get(nextId);
            nextRef?.current?.focus();
        }
    }, []);

    const contextValue: KeyboardNavContextValue = {
        register,
        unregister,
        setElementsOrder,
        getNavProps,
        focusNext,
    };

    return contextValue;
}
